1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return empty array for a single live cell (underpopulation)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should return empty array for two adjacent cells, each with one neighbor (underpopulation)", () => {
10	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
11	  });
12	  it("should keep alive a cell with three live neighbors (survival)", () => {
13	    // ###
14	    // .#.   the focal cell (1,1) has 3 live neighbors -> it survives
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toContainEqual([1, 1]);
16	  });
17	  it("should kill a live cell with more than three live neighbors (overpopulation)", () => {
18	    // ###
19	    // .#.   the focal cell (1,1) has 4 live neighbors -> it dies
20	    // ###
21	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]])).not.toContainEqual([1, 1]);
22	  });
23	  it.todo("should bring to life a dead cell with exactly three live neighbors (reproduction)");
24	  it.todo("should keep a block still life unchanged");
25	  it.todo("should rotate a vertical blinker into a horizontal blinker including negative coordinates");
26	});
27

1	export type Cell = [number, number];
2	
3	const areNeighbors = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
4	  Math.max(Math.abs(x - otherX), Math.abs(y - otherY)) === 1;
5	
6	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
7	  liveCells.filter((other) => areNeighbors(cell, other)).length;
8	
9	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
10	  liveCells.filter((cell) => countLiveNeighbors(cell, liveCells) === 3);
